#include <stdio.h>
#include <string.h>
#define MAX 100
#define MAXM 200
#define MAXN 100
int main() {
    int t = 1;
    while (t--) {
        char setName[20];
        int n, m;
        scanf("%s %d %d", setName, &n, &m);
        int prices[MAXN][MAXM];
        char names[MAXN][20];
        for (int i = 0; i < n; i++) {
            scanf("%s", names[i]);
            for (int j = 0; j < m; j++) {
                scanf("%d", &prices[i][j]);
            }
        }
        int dp[MAXM];
        int prev[MAXM];
        for (int i = 0; i < m; i++) {
            dp[i] = 1000000;
            prev[i] = -1;
        }
        dp[0] = prices[0][0];
        for (int i = 1; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < i; k++) {
                    int cost = dp[k] + prices[j][i] - (prices[j][i] - 100);
                    if (cost < dp[i]) {
                        dp[i] = cost;
                        prev[i] = k;
                    }
                }
            }
        }
        printf("%s\n", setName);
        printf("Tk %d\n", dp[m - 1]);
        int i = m - 1;
        while (i >= 0) {
            printf("%s for %d month(s)\n", names[prev[i]], i - prev[i] + 1);
            i = prev[i];
        }
        printf("\n");
    }
    return 0;
}

