import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = 1;
        while (t-- > 0) {
            String setName = sc.next();
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[][] prices = new int[n][m];
            String[] names = new String[n];
            for (int i = 0; i < n; i++) {
                names[i] = sc.next();
                for (int j = 0; j < m; j++) {
                    prices[i][j] = sc.nextInt();
                }
            }
            int[] dp = new int[m];
            int[] prev = new int[m];
            for (int i = 0; i < m; i++) {
                dp[i] = 1000000;
                prev[i] = -1;
            }
            dp[0] = prices[0][0];
            for (int i = 1; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    for (int k = 0; k < i; k++) {
                        int cost = dp[k] + prices[j][i] - (prices[j][i] - 100);
                        if (cost < dp[i]) {
                            dp[i] = cost;
                            prev[i] = k;
                        }
                    }
                }
            }
            System.out.println(setName);
            System.out.println("Tk " + dp[m - 1]);
            int i = m - 1;
            while (i >= 0) {
                System.out.println(names[prev[i]] + " for " + (i - prev[i] + 1) + " month(s)");
                i = prev[i];
            }
            System.out.println();
        }
    }
}

