const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
function nextLine() {
    return lines[idx++];
}
function nextInt() {
    return parseInt(nextLine());
}
function nextIntArray() {
    return nextLine().split(' ').map(x => parseInt(x));
}
let t = 1;
while (t-- > 0) {
    let setName = nextLine();
    let [n, m] = nextIntArray();
    let prices = new Array(n);
    let names = new Array(n);
    for (let i = 0; i < n; i++) {
        let input = nextLine().split(' ');
        names[i] = input[0];
        prices[i] = input.slice(1).map(x => parseInt(x));
    }
    let dp = new Array(m).fill(1000000);
    let prev = new Array(m).fill(-1);
    dp[0] = prices[0][0];
    for (let i = 1; i < m; i++) {
        for (let j = 0; j < n; j++) {
            for (let k = 0; k < i; k++) {
                let cost = dp[k] + prices[j][i] - (prices[j][i] - 100);
